// $lib/api.ts
import { get } from 'svelte/store';
import { authToken } from '$lib/stores/auth';

async function request<T>(path: string, init: RequestInit = {}, retries = 1, fetcher = fetch): Promise<T> {
  const res = await fetcher(`/api${path}`, {
    ...init,
    headers: { Authorization: `Bearer ${get(authToken)}`, 'Content-Type': 'application/json', ...init.headers },
  });
  if (res.status === 401 && retries > 0) return request<T>(path, init, retries - 1, fetcher);
  if (!res.ok) throw new Error(await res.text());
  return res.json() as Promise<T>;
}

export const api = {
  get: <T>(path: string, fetcher?: typeof fetch) => request<T>(path, {}, 1, fetcher),
  post: <T>(path: string, body: unknown) => request<T>(path, { method: 'POST', body: JSON.stringify(body) }),
};

// $lib/confirm.svelte.ts
type Pending = { message: string; resolve: (ok: boolean) => void } | null;

let pending = $state<Pending>(null);

export const confirmDialog = {
  get pending() { return pending; },
  ask(message: string) {
    return new Promise<boolean>((resolve) => {
      pending = { message, resolve };
    });
  },
  respond(ok: boolean) {
    pending?.resolve(ok);
    pending = null;
  },
};

